import{_ as a,o as s,c as n,a4 as e}from"./chunks/framework.Fmm5XFPO.js";const m=JSON.parse('{"title":"LLD Design Patterns (Easy Analogy Notes)","description":"","frontmatter":{},"headers":[],"relativePath":"Learning/System Design/mynotes.md","filePath":"Learning/System Design/mynotes.md","lastUpdated":1781697439000}'),p={name:"Learning/System Design/mynotes.md"},l=e(`<p>This is a great way to make <strong>LLD interview notes</strong>. I would keep the same style and add <strong>Top 3 Structural</strong> and <strong>Top 3 Behavioral</strong> patterns.</p><h1 id="lld-design-patterns-easy-analogy-notes" tabindex="-1">LLD Design Patterns (Easy Analogy Notes) <a class="header-anchor" href="#lld-design-patterns-easy-analogy-notes" aria-label="Permalink to &quot;LLD Design Patterns (Easy Analogy Notes)&quot;">​</a></h1><hr><h1 id="creational-patterns" tabindex="-1">CREATIONAL PATTERNS <a class="header-anchor" href="#creational-patterns" aria-label="Permalink to &quot;CREATIONAL PATTERNS&quot;">​</a></h1><h1 id="_1-singleton-pattern" tabindex="-1">1. Singleton Pattern <a class="header-anchor" href="#_1-singleton-pattern" aria-label="Permalink to &quot;1. Singleton Pattern&quot;">​</a></h1><h2 id="one-security-guard" tabindex="-1">One Security Guard <a class="header-anchor" href="#one-security-guard" aria-label="Permalink to &quot;One Security Guard&quot;">​</a></h2><p>Imagine a Ryan Square building.</p><p>There should be <strong>only one security guard</strong>.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Block A ----\\</span></span>
<span class="line"><span>Block B ----- &gt; Security Guard (only one security guard for all blocks)</span></span>
<span class="line"><span>Block C ----/</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Everyone uses the same guard.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="rule" tabindex="-1">Rule <a class="header-anchor" href="#rule" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Singleton = &quot;Only one object for everyone.&quot;</p></blockquote><h3 id="when-to-use" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><ul><li>Database connection</li><li>Logger</li><li>Config manager</li></ul><hr><h1 id="_2-factory-pattern" tabindex="-1">2. Factory Pattern <a class="header-anchor" href="#_2-factory-pattern" aria-label="Permalink to &quot;2. Factory Pattern&quot;">​</a></h1><h2 id="restaurant-kitchen" tabindex="-1">Restaurant Kitchen <a class="header-anchor" href="#restaurant-kitchen" aria-label="Permalink to &quot;Restaurant Kitchen&quot;">​</a></h2><p>You don&#39;t cook food yourself.</p><p>You simply say:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Give me Burger&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>or</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&quot;Give me Pizza&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>The kitchen decides:</p><ul><li>ingredients</li><li>cooking process</li><li>oven temperature</li></ul><p>You only ask for the final product.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Customer</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>   v</span></span>
<span class="line"><span>Kitchen (Factory)</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>   +--&gt; Pizza</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>   +--&gt; Burger</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="rule-1" tabindex="-1">Rule <a class="header-anchor" href="#rule-1" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Factory = &quot;You ask, factory creates.&quot;</p></blockquote><h3 id="when-to-use-1" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-1" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>When you have many object types.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Car</span></span>
<span class="line"><span>Bike</span></span>
<span class="line"><span>Truck</span></span>
<span class="line"><span></span></span>
<span class="line"><span>or</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Email</span></span>
<span class="line"><span>SMS</span></span>
<span class="line"><span>Push Notification</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>and don&#39;t want <code>if-else</code> everywhere.</p><hr><h1 id="_3-builder-pattern" tabindex="-1">3. Builder Pattern <a class="header-anchor" href="#_3-builder-pattern" aria-label="Permalink to &quot;3. Builder Pattern&quot;">​</a></h1><h2 id="build-your-own-pc" tabindex="-1">Build Your Own PC <a class="header-anchor" href="#build-your-own-pc" aria-label="Permalink to &quot;Build Your Own PC&quot;">​</a></h2><p>You don&#39;t say:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Give me everything.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>You choose step by step:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU → Intel i9</span></span>
<span class="line"><span>RAM → 32GB</span></span>
<span class="line"><span>SSD → 1TB</span></span>
<span class="line"><span>GPU → RTX 5090</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Then press:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Build</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; CPU</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; RAM</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; SSD</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; GPU</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; Build</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>       v</span></span>
<span class="line"><span>    Computer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h3 id="rule-2" tabindex="-1">Rule <a class="header-anchor" href="#rule-2" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Builder = &quot;Build a complex object step by step.&quot;</p></blockquote><h3 id="when-to-use-2" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-2" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>When an object has lots of optional fields.</p><p>Examples:</p><ul><li>Computer</li><li>House</li><li>SQL Query Builder</li><li>API Request Builder</li></ul><hr><h1 id="structural-patterns" tabindex="-1">STRUCTURAL PATTERNS <a class="header-anchor" href="#structural-patterns" aria-label="Permalink to &quot;STRUCTURAL PATTERNS&quot;">​</a></h1><h1 id="_1-adapter-pattern" tabindex="-1">1. Adapter Pattern <a class="header-anchor" href="#_1-adapter-pattern" aria-label="Permalink to &quot;1. Adapter Pattern&quot;">​</a></h1><h2 id="travel-adapter-power-plug-converter" tabindex="-1">Travel Adapter (Power Plug Converter) <a class="header-anchor" href="#travel-adapter-power-plug-converter" aria-label="Permalink to &quot;Travel Adapter (Power Plug Converter)&quot;">​</a></h2><p>You travel from India to the USA.</p><p>Your charger cannot fit.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Indian Charger</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>       v</span></span>
<span class="line"><span>Travel Adapter</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>       v</span></span>
<span class="line"><span>USA Socket</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>The adapter makes two incompatible things work together.</p><h3 id="rule-3" tabindex="-1">Rule <a class="header-anchor" href="#rule-3" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Adapter = &quot;Convert one interface into another.&quot;</p></blockquote><h3 id="when-to-use-3" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-3" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><ul><li>Third-party APIs</li><li>Legacy systems</li><li>Different data formats</li></ul><p>Examples:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Old Payment API</span></span>
<span class="line"><span>New Payment API</span></span>
<span class="line"><span></span></span>
<span class="line"><span>or</span></span>
<span class="line"><span></span></span>
<span class="line"><span>XML -&gt; JSON</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><hr><h1 id="_2-decorator-pattern" tabindex="-1">2. Decorator Pattern <a class="header-anchor" href="#_2-decorator-pattern" aria-label="Permalink to &quot;2. Decorator Pattern&quot;">​</a></h1><h2 id="pizza-toppings" tabindex="-1">Pizza Toppings <a class="header-anchor" href="#pizza-toppings" aria-label="Permalink to &quot;Pizza Toppings&quot;">​</a></h2><p>You start with a plain pizza.</p><p>Then add toppings.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pizza</span></span>
<span class="line"><span></span></span>
<span class="line"><span>+ Cheese</span></span>
<span class="line"><span></span></span>
<span class="line"><span>+ Mushroom</span></span>
<span class="line"><span></span></span>
<span class="line"><span>+ Olives</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plain Pizza</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>      +--&gt; Cheese</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>      +--&gt; Mushroom</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>      +--&gt; Olives</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>You keep adding features without changing the original pizza.</p><h3 id="rule-4" tabindex="-1">Rule <a class="header-anchor" href="#rule-4" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Decorator = &quot;Add features without modifying the original object.&quot;</p></blockquote><h3 id="when-to-use-4" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-4" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>Examples:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Coffee + Milk</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Coffee + Sugar</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Coffee + Cream</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>or</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Logger</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Logger + Timestamp</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Logger + File Logging</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h1 id="_3-facade-pattern" tabindex="-1">3. Facade Pattern <a class="header-anchor" href="#_3-facade-pattern" aria-label="Permalink to &quot;3. Facade Pattern&quot;">​</a></h1><h2 id="tv-remote" tabindex="-1">TV Remote <a class="header-anchor" href="#tv-remote" aria-label="Permalink to &quot;TV Remote&quot;">​</a></h2><p>Inside a TV there are many systems.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TV</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Sound System</span></span>
<span class="line"><span></span></span>
<span class="line"><span>HDMI</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Display</span></span>
<span class="line"><span></span></span>
<span class="line"><span>WiFi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>But you don&#39;t control them individually.</p><p>You simply use one remote.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> v</span></span>
<span class="line"><span>TV Remote (Facade)</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; TV</span></span>
<span class="line"><span> +--&gt; Sound</span></span>
<span class="line"><span> +--&gt; HDMI</span></span>
<span class="line"><span> +--&gt; WiFi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="rule-5" tabindex="-1">Rule <a class="header-anchor" href="#rule-5" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Facade = &quot;One simple interface for a complex system.&quot;</p></blockquote><h3 id="when-to-use-5" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-5" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>Examples:</p><ul><li>Payment service</li><li>Video processing service</li><li>Booking service</li></ul><hr><h1 id="behavioral-patterns" tabindex="-1">BEHAVIORAL PATTERNS <a class="header-anchor" href="#behavioral-patterns" aria-label="Permalink to &quot;BEHAVIORAL PATTERNS&quot;">​</a></h1><h1 id="_1-observer-pattern" tabindex="-1">1. Observer Pattern <a class="header-anchor" href="#_1-observer-pattern" aria-label="Permalink to &quot;1. Observer Pattern&quot;">​</a></h1><h2 id="youtube-subscribers" tabindex="-1">YouTube Subscribers <a class="header-anchor" href="#youtube-subscribers" aria-label="Permalink to &quot;YouTube Subscribers&quot;">​</a></h2><p>You subscribe to a channel.</p><p>Whenever the creator uploads a video, everyone gets notified.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>YouTube Channel</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>      +--&gt; User A</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>      +--&gt; User B</span></span>
<span class="line"><span>      |</span></span>
<span class="line"><span>      +--&gt; User C</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="rule-6" tabindex="-1">Rule <a class="header-anchor" href="#rule-6" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Observer = &quot;One changes, many get notified.&quot;</p></blockquote><h3 id="when-to-use-6" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-6" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>Examples:</p><ul><li>Notifications</li><li>Event systems</li><li>Stock price updates</li></ul><hr><h1 id="_2-strategy-pattern" tabindex="-1">2. Strategy Pattern <a class="header-anchor" href="#_2-strategy-pattern" aria-label="Permalink to &quot;2. Strategy Pattern&quot;">​</a></h1><h2 id="google-maps-route-selection" tabindex="-1">Google Maps Route Selection <a class="header-anchor" href="#google-maps-route-selection" aria-label="Permalink to &quot;Google Maps Route Selection&quot;">​</a></h2><p>You want to go somewhere.</p><p>You can choose:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Car</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Bike</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Walk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> v</span></span>
<span class="line"><span>Google Maps</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; Car Route</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; Bike Route</span></span>
<span class="line"><span> |</span></span>
<span class="line"><span> +--&gt; Walking Route</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>The algorithm changes but the goal stays the same.</p><h3 id="rule-7" tabindex="-1">Rule <a class="header-anchor" href="#rule-7" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Strategy = &quot;Choose a behavior at runtime.&quot;</p></blockquote><h3 id="when-to-use-7" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-7" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>Examples:</p><ul><li>Payment methods</li><li>Sorting algorithms</li><li>Search algorithms</li></ul><hr><h1 id="_3-command-pattern" tabindex="-1">3. Command Pattern <a class="header-anchor" href="#_3-command-pattern" aria-label="Permalink to &quot;3. Command Pattern&quot;">​</a></h1><h2 id="restaurant-waiter" tabindex="-1">Restaurant Waiter <a class="header-anchor" href="#restaurant-waiter" aria-label="Permalink to &quot;Restaurant Waiter&quot;">​</a></h2><p>You don&#39;t go to the chef.</p><p>You tell the waiter.</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Customer</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>   v</span></span>
<span class="line"><span>Waiter (Command)</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>   v</span></span>
<span class="line"><span>Chef</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>The waiter carries your request.</p><h3 id="rule-8" tabindex="-1">Rule <a class="header-anchor" href="#rule-8" aria-label="Permalink to &quot;Rule&quot;">​</a></h3><blockquote><p>Command = &quot;Convert a request into an object.&quot;</p></blockquote><h3 id="when-to-use-8" tabindex="-1">When to use <a class="header-anchor" href="#when-to-use-8" aria-label="Permalink to &quot;When to use&quot;">​</a></h3><p>Examples:</p><ul><li>Undo/Redo</li><li>Queue systems</li><li>Task schedulers</li></ul><hr><h1 id="_30-second-interview-cheat-sheet" tabindex="-1">30-Second Interview Cheat Sheet <a class="header-anchor" href="#_30-second-interview-cheat-sheet" aria-label="Permalink to &quot;30-Second Interview Cheat Sheet&quot;">​</a></h1><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CREATIONAL</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need ONE object?</span></span>
<span class="line"><span>→ Singleton</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need DIFFERENT objects?</span></span>
<span class="line"><span>→ Factory</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need a BIG object built in steps?</span></span>
<span class="line"><span>→ Builder</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>STRUCTURAL</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need to CONNECT incompatible things?</span></span>
<span class="line"><span>→ Adapter</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need to ADD features?</span></span>
<span class="line"><span>→ Decorator</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need to HIDE complexity?</span></span>
<span class="line"><span>→ Facade</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>BEHAVIORAL</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need NOTIFICATIONS?</span></span>
<span class="line"><span>→ Observer</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need to SWITCH algorithms?</span></span>
<span class="line"><span>→ Strategy</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need to EXECUTE requests?</span></span>
<span class="line"><span>→ Command</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br></div></div><ul><li><a href="./Examples/Car_rental.html"><strong>Car Rental</strong></a></li></ul>`,126),i=[l];function r(t,c,o,u,b,d){return s(),n("div",null,i)}const g=a(p,[["render",r]]);export{m as __pageData,g as default};
